import{_ as a,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"扭曲魔眼","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/3.瞳术/扭曲魔眼.md","filePath":"4.资源分区/3.瞳术/扭曲魔眼.md"}'),d={name:"4.资源分区/3.瞳术/扭曲魔眼.md"};function p(b,e,l,_,i,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"扭曲魔眼",tabindex:"-1"},[s("扭曲魔眼 "),r("a",{class:"header-anchor",href:"#扭曲魔眼","aria-label":'Permalink to "扭曲魔眼"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风021")])])],-1),o('<h1 id="扭曲魔眼-1" tabindex="-1">扭曲魔眼 <a class="header-anchor" href="#扭曲魔眼-1" aria-label="Permalink to &quot;扭曲魔眼&quot;">​</a></h1><p>扭曲魔眼（主神版）<br> 本质：魔幻本质<br> 描述：以视线开启回转轴：左眼为左回转，右眼为右回转，可扭曲注视事物存在的能力。<br> 扭曲是极其简单的行为，但记录事物的存在再加以影响是极为困难的行为，这就导致了往往拥有者的感知能力限制了扭曲魔眼的发挥。<br> 扭曲魔眼的价格等同标准瞳术模板价格。</p><p>D级<br> 描述： 开启本瞳术时，别人可以看到你的瞳孔中有不断扭曲成螺旋的彩色光圈，在此时你只能看到包裹物体的轮廓线，但你可以随时在自己视线中描绘回转轴，你可以如常看到灵体。<br> 扭曲：开启瞳术是一个自由动作，瞳术开启期间，你获得基于视觉的D级特异本质侦测能力，同时具有【黑暗视觉】的效果，在感知相关检定上获得2DP内在加值。<br> 开启瞳术后，你获得了一种新的攻击能力，通过感知+洞察+专业：瞳力+辅助专业：魔力爆发（专注）的攻击检定，能力的攻击射程为20米，武器伤害为3L，造成力场伤害。</p><p>C级<br> 描述：现在你可以在一个物体上开启两个回转轴，从两个螺旋的交界处捻断物体。<br> 扭曲-提升：由于扭曲力量的提升，你在使用上一等级提供的新建攻击模式时，攻击获得5点破甲效果，射程改为【20+传奇感知*5米】。<br> 瞳力提升：你再获得2DP感知检定上的内在加值，在上一等级获得的侦测能力提升至C级，同时可以透视原本会阻隔视线的屏障，如隔着墙壁或魔法屏障看透后面的事物，这是基于视觉侦测能力的【透视】，会被更高等级的屏障阻隔视线。</p><p>B级<br> 描述：“哎呀……一不小心就快要扭断了，你还好吗？”<br> 瞳力提升：提供的侦测提升至B级。<br> 扭曲-提升：你的扭曲魔眼攻击检定是一个消费标准动作，不能附带其他招式的普通攻击，本次攻击中具有【传送攻击】性质，附带【幻灭】特性。此外，你在之前等级获得的【破甲5】提升至【破甲10】，若计算对应防御后仍有剩余，则转为等量的攻击检定上的增强加值。<br> 本次攻击可以同时对前方扇形范围内的所有敌人造成伤害，附带等同伤害出目的【纠缠】不良点数，你可以选择让目标使用反射豁免伤害，而不是进行正常防御减少伤害流程。</p><p>A级<br> 描述：与另一种扭曲魔眼的性质不同，这一魔眼的性质是对于【存在】的直接干涉。正是因此，只要看到就能造成杀伤，是与直死魔眼产生近似结果的产物。虽然不能立刻杀死对方，却也有着足够的杀伤能力。<br> 扭曲-极：当你进行扭曲魔眼的攻击时，你可以使在上一等级中获得的破甲提升至【破甲20】。<br> 此外，你可以使扭曲魔眼进行的攻击检定成功数增加一半，这一效果每轮只会生效一次。<br> 瞳力提升-极：现在扭曲魔眼的射程提升至敏感范围，之前等级提供的侦测等级提升至A级。若你不具有【灵感视觉】，则获得【灵感视觉】。若已具有，则改为再获得5DP感知相关检定上的内在加值。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=a(d,[["render",p]]);export{f as __pageData,m as default};
